#include <stdio.h>

int main() {
  int a = 5, b = 3, result;

  asm ("movl %1, %%eax;"
       "addl %2, %%eax;"
       "movl %%eax, %0;"
       : "=r" (result) /* Çıxış */
       : "r" (a), "r" (b) /* Giriş */
       : "%eax" /* İstifadə olunan registr */
  );

  printf("Nəticə: %d\n", result);
  return 0;
}
// Output:
// Nəticə: 8

